/*! marked.js minimal — inline version for offline use */
(function(){
  const marked = {
    parse: function(src) {
      return src
        // Fenced code blocks
        .replace(/```(\w*)\n([\s\S]*?)```/gm, (_, lang, code) =>
          `<pre><code class="language-${lang}">${escHtml(code.trim())}</code></pre>`)
        // Inline code
        .replace(/`([^`]+)`/g, (_, c) => `<code>${escHtml(c)}</code>`)
        // Headings
        .replace(/^#{6}\s(.+)$/gm, '<h6>$1</h6>')
        .replace(/^#{5}\s(.+)$/gm, '<h5>$1</h5>')
        .replace(/^#{4}\s(.+)$/gm, '<h4>$1</h4>')
        .replace(/^#{3}\s(.+)$/gm, '<h3>$1</h3>')
        .replace(/^#{2}\s(.+)$/gm, '<h2>$1</h2>')
        .replace(/^#{1}\s(.+)$/gm, '<h1>$1</h1>')
        // Bold & italic
        .replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
        .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
        .replace(/\*(.+?)\*/g, '<em>$1</em>')
        // Blockquote
        .replace(/^>\s(.+)$/gm, '<blockquote><p>$1</p></blockquote>')
        // HR
        .replace(/^---+$/gm, '<hr/>')
        // Unordered lists
        .replace(/(^[-*+]\s.+$\n?)+/gm, m => `<ul>${m.replace(/^[-*+]\s(.+)$/gm,'<li>$1</li>')}</ul>`)
        // Ordered lists
        .replace(/(^\d+\.\s.+$\n?)+/gm, m => `<ol>${m.replace(/^\d+\.\s(.+)$/gm,'<li>$1</li>')}</ol>`)
        // Links
        .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>')
        // Paragraphs
        .replace(/\n\n(.+?)(?=\n\n|$)/gs, (_, p) => {
          const trimmed = p.trim();
          if (/^<(h[1-6]|ul|ol|pre|blockquote|hr)/.test(trimmed)) return '\n\n' + trimmed;
          return `\n\n<p>${trimmed.replace(/\n/g,' ')}</p>`;
        });
    }
  };

  function escHtml(s) {
    return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }

  window.marked = marked;
})();
